const incoming = $input.first().json ?? {};
const body = incoming.body ?? incoming ?? {};

const toArray = (value) => {
  if (Array.isArray(value)) return value.filter((item) => item !== null && item !== undefined && item !== '');
  if (typeof value === 'string') {
    return value.split(',').map((item) => item.trim()).filter(Boolean);
  }
  return [];
};

const truncate = (value, max = 120) => {
  const text = String(value ?? '').trim();
  if (!text) return '';
  return text.length > max ? `${text.slice(0, max - 1)}…` : text;
};

const relabelBusinessType = (value) => {
  const text = String(value ?? '').trim();
  if (!text) return '';
  return text === '관리형' ? '관리형 스터디카페' : text;
};

const buildProtectedImageUrl = (value) => {
  const url = String(value ?? '').trim();
  if (!url || !url.includes('/image/upload/') || url.includes('/l_text:Arial_28_bold:FINDGAGU')) return url;
  const transformation = [
    'f_auto',
    'q_auto',
    'fl_lossy',
    'w_1280',
    'c_limit',
    'l_text:Arial_28_bold:FINDGAGU',
    'co_rgb:ffffff',
    'o_28',
    'g_south_east',
    'x_28',
    'y_24',
  ].join(',');
  return url.replace('/image/upload/', `/image/upload/${transformation}/`);
};

const normalizeImage = (image, index, forcedRole = null) => {
  if (!image) return null;
  if (typeof image === 'string') {
    return {
      id: `img-${index + 1}`,
      url: image,
      delivery_url: buildProtectedImageUrl(image),
      caption: '',
      product_name: '',
      color_name: '',
      before_after_role: forcedRole,
      before_after_group_id: '',
      order: index + 1,
    };
  }

  const url = image.url ?? image.secure_url ?? image.image_url ?? image.src ?? '';
  if (!url) return null;

  const role = forcedRole
    ?? (image.before_after_role === 'before' || image.before_after_role === 'after' ? image.before_after_role : null)
    ?? (image.beforeAfterRole === 'before' || image.beforeAfterRole === 'after' ? image.beforeAfterRole : null);

  return {
    id: image.id ?? image.asset_id ?? image.public_id ?? `img-${index + 1}`,
    url,
    delivery_url: buildProtectedImageUrl(url),
    caption: image.caption ?? image.description ?? '',
    product_name: image.product_name ?? image.productName ?? '',
    color_name: image.color_name ?? image.colorName ?? '',
    before_after_role: role,
    before_after_group_id: image.before_after_group_id ?? image.beforeAfterGroupId ?? image.pair_id ?? image.pairId ?? '',
    order: image.order ?? index + 1,
  };
};

const rawBeforeImages = toArray(body.before_images ?? body.beforeImages)
  .map((image, index) => normalizeImage(image, index, 'before'))
  .filter(Boolean);
const rawAfterImages = toArray(body.after_images ?? body.afterImages)
  .map((image, index) => normalizeImage(image, index, 'after'))
  .filter(Boolean);
const rawImages = [
  ...toArray(body.representative_images),
  ...toArray(body.source_images),
  ...toArray(body.images),
].map((image, index) => normalizeImage(image, index)).filter(Boolean);

const maxImagesRaw = Number(body.max_images ?? body.maxImages ?? 8);
const maxImages = Number.isFinite(maxImagesRaw) ? Math.max(1, Math.min(maxImagesRaw, 12)) : 8;
const selectedBeforeImagesRaw = rawBeforeImages.slice(0, Math.min(maxImages, 4));
const selectedAfterImagesRaw = (rawAfterImages.length ? rawAfterImages : rawImages.filter((image) => image.before_after_role !== 'before')).slice(0, maxImages);
const selectedImagesRaw = selectedBeforeImagesRaw.length
  ? [...selectedBeforeImagesRaw, ...selectedAfterImagesRaw]
  : selectedAfterImagesRaw;

const publicSiteName = body.site_name ?? body.siteName ?? body.external_display_name ?? body.externalDisplayName ?? body.showroom_name ?? body.showroomName ?? '파인드가구 쇼룸';
const internalSiteName = body.internal_site_name ?? body.internalSiteName ?? '';
const locationKr = body.location_kr ?? body.locationKr ?? body.location ?? '';
const businessTypeKr = relabelBusinessType(body.business_type_kr ?? body.businessTypeKr ?? body.business_type ?? body.businessType ?? '');
const productNames = toArray(body.product_names ?? body.productNames);
const colorNames = toArray(body.color_names ?? body.colorNames);
const faqTopics = toArray(body.faq_topics ?? body.faqTopics);
const seoDescription = String(body.seo_description ?? body.seoDescription ?? '').trim();
const comparisonFocus = toArray(body.comparison_focus ?? body.comparisonFocus);
const primaryKeyword = body.primary_keyword ?? body.primaryKeyword ?? productNames[0] ?? publicSiteName;
const ctaText = body.cta_text ?? body.ctaText ?? '비슷한 사례를 더 보려면 파인드가구 홈페이지 쇼룸에서 다양한 현장 사례를 먼저 확인해보세요.';
const reviewEmail = body.review_email ?? body.reviewEmail ?? 'admin@findgagu.com';
const titleHint = body.title_hint ?? body.titleHint ?? `${publicSiteName} 사례 콘텐츠`;
const contentItemId = body.content_item_id ?? body.contentItemId ?? body.showroom_group_key ?? body.showroomGroupKey ?? `manual-${Date.now()}`;
const showroomGroupKey = body.showroom_group_key ?? body.showroomGroupKey ?? contentItemId;
const qualityThresholdRaw = Number(body.quality_threshold ?? body.qualityThreshold ?? 85);
const qualityThreshold = Number.isFinite(qualityThresholdRaw) ? qualityThresholdRaw : 85;
const beforeAfterAvailable = selectedBeforeImagesRaw.length > 0 && selectedAfterImagesRaw.length > 0;

const buildDefaultAlt = (image, index) => {
  const roleLabel = image.before_after_role === 'before'
    ? '비포어'
    : image.before_after_role === 'after'
      ? '애프터'
      : '현장';
  const parts = [publicSiteName, roleLabel, locationKr, businessTypeKr, image.product_name, image.color_name, image.caption]
    .map((item) => String(item ?? '').trim())
    .filter(Boolean);
  return truncate(parts.join(' - ') || `${publicSiteName} ${roleLabel} 이미지 ${index + 1}`, 110);
};

const selectedImages = selectedImagesRaw.map((image, index) => ({
  ...image,
  default_alt: buildDefaultAlt(image, index),
}));

const imageMetaLines = selectedImages.length
  ? selectedImages.map((image, index) => {
      const roleLabel = image.before_after_role === 'before' ? 'before' : 'after';
      const productText = roleLabel === 'before' ? '추정 금지' : (image.product_name || '미기재');
      const colorText = roleLabel === 'before' ? '추정 금지' : (image.color_name || '미기재');
      return [
        `이미지${index + 1}`,
        `- role: ${roleLabel}`,
        `- 제품명: ${productText}`,
        `- 색상: ${colorText}`,
        `- pair_id: ${image.before_after_group_id || '없음'}`,
        `- 설명: ${image.caption || '없음'}`,
      ].join('\n');
    }).join('\n\n')
  : '이미지 메타데이터 없음';

const modeLabel = beforeAfterAvailable ? '비포어/애프터 비교형 사례' : '일반 시공 사례';
const sectionRule = beforeAfterAvailable
  ? '본문 H2는 최대 4개로 제한하고, 전후 비교 섹션 1개를 포함한다.'
  : '본문 H2는 최대 3개로 제한하고, 전후 비교 섹션은 만들지 않는다.';

const promptText = [
  '당신은 교육공간과 스터디카페 기획에 강한 콘텐츠 에디터입니다.',
  '독자는 글보다 먼저 사진을 보고, 신뢰가 생기면 내용을 읽고, 마지막에 홈페이지 안의 온라인 쇼룸에서 더 비교해볼지 판단합니다.',
  '따라서 본문은 사진을 먼저 보고 읽기 쉬운 구조를 전제로 작성하세요.',
  '출력은 네이버 블로그 발행 초안 기준으로 작성하세요.',
  'SEO, AEO, GEO를 함께 만족해야 하며 첫 문단 3~5줄 안에서 핵심 답을 먼저 제시하세요.',
  '제목과 도입부는 검색 사용자의 질문 의도에 바로 답하는 설명형 문장으로 시작하세요.',
  '대표 이미지로 가장 적합한 컷 1장을 함께 고르고, 그 이유도 짧게 설명하세요.',
  '',
  `[콘텐츠 모드]`,
  modeLabel,
  '',
  `[공개 표기명 규칙]`,
  `공개용 현장명: ${publicSiteName}`,
  `내부 현장명: ${internalSiteName || '없음'}`,
  '응답에는 공개용 현장명만 사용하고, 내부 현장명은 절대 쓰지 마세요.',
  '',
  `[프로젝트 정보]`,
  `지역: ${locationKr || '미기재'}`,
  `업종: ${businessTypeKr || '미기재'}`,
  `핵심 키워드: ${primaryKeyword || '미기재'}`,
  `제품명: ${productNames.length ? productNames.join(', ') : '미기재'}`,
  `색상: ${colorNames.length ? colorNames.join(', ') : '미기재'}`,
  `비교 초점: ${comparisonFocus.length ? comparisonFocus.join(', ') : '공간 구성 변화, 동선 변화, 분위기 변화'}`,
  `SEO 설명: ${seoDescription || '미기재'}`,
  `CTA: ${ctaText}`,
  '',
  `[이미지별 메타데이터]`,
  imageMetaLines,
  '',
  `[절대 규칙]`,
  '1. 지역과 업종은 한국어로만 작성한다.',
  '2. 자재, 마감, 구조, 성능은 사진이나 메타데이터로 확인되지 않으면 추정하지 않는다.',
  '3. 메타데이터에 없는 제품명/색상은 만들지 않는다.',
  '4. before 이미지는 관찰 가능한 사실만 쓴다.',
  '5. before 이미지에 제품명, 브랜드명, 자재명, 색상명을 추정해서 쓰지 않는다.',
  '6. after 이미지만 제공된 메타데이터를 활용해 제품명과 색상을 구체적으로 반영한다.',
  '7. "첫 번째 사진", "두 번째 이미지" 같은 순번 표현은 금지한다.',
  '8. body_html은 HTML 조각으로 작성하고 html/body 태그는 넣지 않는다.',
  `9. ${sectionRule}`,
  '10. 기존 구조처럼 "한눈에 보기", "프로젝트 소개", "공간 기획 포인트", "공간 기획의 디테일"을 모두 분리하지 말고 묶어서 줄인다.',
  '11. 사진 설명 뒤에는 독자가 홈페이지 안의 온라인 쇼룸에서 비슷한 사례를 더 비교해보고 싶어질 만한 이유를 자연스럽게 이어준다.',
  '12. human_touch는 과장된 에피소드 창작이 아니라, 현장감이 느껴지는 짧은 코멘트로만 쓴다.',
  '13. 업종 메타가 "관리형 스터디카페"이면 본문과 제목에서도 반드시 그 표현만 쓰고 "관리형 학습공간" 표현은 쓰지 않는다.',
  '',
  `[본문 구조]`,
  '1. 도입 1블록: 현장 성격과 핵심 포인트를 3~4문장으로 요약',
  beforeAfterAvailable
    ? '2. 변화 포인트 1블록: 전후 비교 핵심만 3~5개로 정리'
    : '2. 핵심 포인트 1블록: 이 현장에서 눈여겨볼 점을 3~5개로 정리',
  '3. 공간별 설명 1블록: 각 사진 기반의 독립 단락으로 구성',
  '4. 온라인 쇼룸 유도 1블록: 홈페이지 안에서 비슷한 사례를 더 비교해볼 이유와 CTA 포함',
  '',
  `[추가 작성 규칙]`,
  '1. featured_answer: 검색/요약에 바로 노출될 수 있는 2~3문장 답변형 요약. 오프라인 방문 유도처럼 쓰지 말고 온라인 사례 비교 맥락으로 작성',
  '2. faq_qas: 3개 이상',
  '3. geo_points: 3~5개. 지역 키워드를 줄바꿈으로 나열하지 말고, 검색 사용자에게 도움이 되는 짧은 문장형 포인트로 작성',
  '4. image_alts: 이미지 수와 동일한 개수',
  '5. image_captions는 사진 먼저 보게 만드는 짧고 선명한 문장형으로',
  '6. hashtags는 3개 안팎으로 간결하게',
  '7. 여기서 말하는 쇼룸은 오프라인 전시장이 아니라 파인드가구 홈페이지 안의 온라인 사례 쇼룸이다. 오프라인 방문, 실물 체험, 직접 와서 본다 같은 표현은 금지한다.',
  '8. geo_points와 featured_answer에는 지역명만 나열하지 말고, 이 사례를 온라인에서 왜 더 살펴볼 가치가 있는지 문장형으로 설명한다.',
  '9. representative_image_index는 현재 전달된 이미지 배열 기준 1부터 시작하는 번호로 반환한다.',
  '10. representative_image_reason은 왜 그 컷이 대표 이미지로 적합한지 한두 문장으로 작성한다.',
  '11. image_order는 네이버 블로그 본문에 추천하는 이미지 노출 순서를 1-based 배열로 반환한다.',
  '',
  `[출력 JSON 스키마]`,
  '{',
  '  "title": "string",',
  '  "summary": "string",',
  '  "featured_answer": "string",',
  '  "before_after_points": ["string"],',
  '  "body_html": "string",',
  '  "social_text": "string",',
  '  "hashtags": ["#태그1", "#태그2", "#태그3"],',
  '  "seo_keywords": ["string"],',
  '  "geo_points": ["string"],',
  '  "faq_qas": [{"question": "string", "answer": "string"}],',
  '  "image_alts": ["string"],',
  '  "image_captions": ["string"],
    "representative_image_index": 1,
    "representative_image_reason": "string",
    "image_order": [1, 2, 3],',
  '  "human_touch": "string"',
  '}',
  '',
  '반드시 JSON만 반환하세요.',
].join('\n');

const userContent = [
  ...selectedImages.map((image) => ({
    type: 'image_url',
    image_url: {
      url: image.url,
    },
  })),
  {
    type: 'text',
    text: promptText,
  },
];

const draftRequestBody = {
  model: body.model ?? 'gpt-4.1',
  temperature: 0.7,
  max_tokens: 8192,
  response_format: {
    type: 'json_object',
  },
  messages: [
    {
      role: 'user',
      content: userContent,
    },
  ],
};

return [{
  json: {
    requestSource: incoming.body ? 'webhook' : 'manual',
    contentItemId,
    showroomGroupKey,
    siteName: publicSiteName,
    internalSiteName,
    locationKr,
    businessTypeKr,
    productNames,
    colorNames,
    faqTopics,
    seoDescription,
    comparisonFocus,
    beforeAfterAvailable,
    beforeImages: selectedImages.filter((image) => image.before_after_role === 'before'),
    afterImages: selectedImages.filter((image) => image.before_after_role !== 'before'),
    primaryKeyword,
    ctaText,
    reviewEmail,
    titleHint,
    selectedImages,
    imageCount: selectedImages.length,
    qualityThreshold,
    draftRequestBody,
  },
}];

const normalized = $('입력 정규화 및 샘플 보강').first().json;
const response = $input.first().json ?? {};

const stripCodeFences = (value) => {
  if (typeof value !== 'string') return '';
  return value.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
};

const rawContent = stripCodeFences(response.choices?.[0]?.message?.content ?? '');

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (error) {
  parsed = {
    title: normalized.titleHint,
    summary: '',
    featured_answer: '',
    before_after_points: [],
    body_html: rawContent,
    social_text: '',
    hashtags: [],
    seo_keywords: [],
    geo_points: [],
    faq_qas: [],
    image_alts: [],
    image_captions: [],
    human_touch: '',
  };
}

const toTextArray = (value) => {
  if (Array.isArray(value)) return value.map((item) => String(item).trim()).filter(Boolean);
  if (typeof value === 'string') return value.split(/[\n,]/).map((item) => item.trim()).filter(Boolean);
  return [];
};

const normalizeFaqs = (value) => {
  if (!Array.isArray(value)) return [];
  return value
    .map((item) => ({
      question: String(item?.question ?? item?.q ?? '').trim(),
      answer: String(item?.answer ?? item?.a ?? '').trim(),
    }))
    .filter((item) => item.question && item.answer)
    .slice(0, 5);
};

const truncate = (value, max = 125) => {
  const text = String(value ?? '').trim();
  if (!text) return '';
  return text.length > max ? `${text.slice(0, max - 1)}…` : text;
};

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');

const escapeAttr = (value) => escapeHtml(value).replace(/\n/g, ' ');

const emailImageStyle = 'width: 100%; max-width: 640px; height: auto; display: block; margin: 16px auto; border-radius: 18px; -webkit-user-select: none; user-select: none; -webkit-user-drag: none;';
const figureStyle = 'margin: 0 0 24px; text-align: center;';
const captionStyle = 'font-size: 12px; line-height: 1.7; color: #555; text-align: center; margin-top: 8px; padding: 0 4px;';
const sectionStyle = 'margin: 0 0 28px;';
const headingStyle = 'font-size: 22px; line-height: 1.45; margin: 0 0 14px; color: #111;';
const subHeadingStyle = 'font-size: 19px; line-height: 1.5; margin: 0 0 12px; color: #111;';
const paragraphStyle = 'font-size: 16px; line-height: 1.9; color: #222; margin: 0 0 16px;';
const listStyle = 'font-size: 16px; line-height: 1.9; color: #222; padding-left: 20px; margin: 0 0 16px;';
const listItemStyle = 'margin: 0 0 10px;';
const quoteStyle = 'font-size: 15px; line-height: 1.85; color: #374151; margin: 0 0 18px; padding: 14px 16px; border-left: 3px solid #d1d5db; background: #f8fafc;';

const mergeInlineStyle = (tag, styleText) => {
  const styleRegex = /\sstyle\s*=\s*([\"\'])(.*?)\1/i;
  if (styleRegex.test(tag)) {
    return tag.replace(styleRegex, (_match, quote, styles) => {
      const merged = `${String(styles ?? '').trim().replace(/;?$/, ';')} ${styleText}`.trim();
      return ` style=${quote}${merged}${quote}`;
    });
  }
  return tag.replace(/\s*\/?>$/, (ending) => ` style=\"${styleText}\"${ending.includes('/') ? ' />' : '>'}`);
};

const enforceEmailImageSizing = (html) => {
  if (typeof html !== 'string' || !html.trim()) return '';
  return html
    .replace(/<section\b[^>]*>/gi, (tag) => mergeInlineStyle(tag, sectionStyle))
    .replace(/<article\b[^>]*>/gi, (tag) => mergeInlineStyle(tag, sectionStyle))
    .replace(/<h2\b[^>]*>/gi, (tag) => mergeInlineStyle(tag, headingStyle))
    .replace(/<h3\b[^>]*>/gi, (tag) => mergeInlineStyle(tag, subHeadingStyle))
    .replace(/<p\b[^>]*>/gi, (tag) => mergeInlineStyle(tag, paragraphStyle))
    .replace(/<ul\b[^>]*>/gi, (tag) => mergeInlineStyle(tag, listStyle))
    .replace(/<ol\b[^>]*>/gi, (tag) => mergeInlineStyle(tag, listStyle))
    .replace(/<li\b[^>]*>/gi, (tag) => mergeInlineStyle(tag, listItemStyle))
    .replace(/<blockquote\b[^>]*>/gi, (tag) => mergeInlineStyle(tag, quoteStyle))
    .replace(/<figure\b[^>]*>/gi, (tag) => mergeInlineStyle(tag, figureStyle))
    .replace(/<figcaption\b[^>]*>/gi, (tag) => mergeInlineStyle(tag, captionStyle))
    .replace(/<img\b[^>]*>/gi, (tag) => {
      let nextTag = tag
        .replace(/\swidth\s*=\s*([\"\']).*?\1/gi, '')
        .replace(/\sheight\s*=\s*([\"\']).*?\1/gi, '');

      nextTag = mergeInlineStyle(nextTag, emailImageStyle);

      if (!/\swidth\s*=\s*([\"\']).*?\1/i.test(nextTag)) {
        nextTag = nextTag.replace(/<img/i, '<img width=\"640\"');
      }

      if (!/\salt\s*=\s*([\"\']).*?\1/i.test(nextTag)) {
        nextTag = nextTag.replace(/<img/i, '<img alt=\"현장 사진\"');
      }

      if (!/\sloading\s*=\s*([\"\']).*?\1/i.test(nextTag)) {
        nextTag = nextTag.replace(/<img/i, '<img loading=\"lazy\"');
      }

      if (!/\sdraggable\s*=\s*([\"\']).*?\1/i.test(nextTag)) {
        nextTag = nextTag.replace(/<img/i, '<img draggable=\"false\"');
      }

      return nextTag;
    });
};

const title = parsed.title ?? parsed.blog_title ?? normalized.titleHint;
const summary = parsed.summary ?? parsed.excerpt ?? '';
const featuredAnswer = parsed.featured_answer ?? parsed.featuredAnswer ?? summary;
const beforeAfterPoints = normalized.beforeAfterAvailable
  ? toTextArray(parsed.before_after_points ?? parsed.beforeAfterPoints).slice(0, 5)
  : [];
const socialText = parsed.social_text ?? parsed.socialText ?? '';
const hashtags = toTextArray(parsed.hashtags).slice(0, 3);
const seoKeywords = toTextArray(parsed.seo_keywords ?? parsed.seoKeywords);
const geoPoints = toTextArray(parsed.geo_points ?? parsed.geoPoints).slice(0, 5);
const faqQas = normalizeFaqs(parsed.faq_qas ?? parsed.faqQas);
const humanTouch = String(parsed.human_touch ?? parsed.humanTouch ?? '').trim();
const selectedImages = Array.isArray(normalized.selectedImages) ? normalized.selectedImages : [];
const parseImageIndex = (value, max) => {
  const parsed = Number.parseInt(String(value ?? ''), 10);
  if (!Number.isFinite(parsed) || parsed < 1 || parsed > max) return null;
  return parsed;
};
const parseImageOrder = (value, max) => {
  if (!Array.isArray(value)) return [];
  const seen = new Set();
  return value
    .map((entry) => parseImageIndex(entry, max))
    .filter((entry) => {
      if (!entry || seen.has(entry)) return false;
      seen.add(entry);
      return true;
    });
};
const representativeImageIndex =
  parseImageIndex(
    parsed.representative_image_index
    ?? parsed.representativeImageIndex
    ?? parsed.hero_image_index
    ?? parsed.heroImageIndex,
    selectedImages.length
  )
  ?? (selectedImages.length > 0 ? 1 : null);
const representativeImageReason = String(
  parsed.representative_image_reason
  ?? parsed.representativeImageReason
  ?? parsed.hero_image_reason
  ?? parsed.heroImageReason
  ?? ''
).trim();
const imageOrder = parseImageOrder(parsed.image_order ?? parsed.imageOrder, selectedImages.length);
const selectedImagesForRender = imageOrder.length > 0
  ? imageOrder.map((index) => selectedImages[index - 1]).filter(Boolean)
  : representativeImageIndex
    ? [
        selectedImages[representativeImageIndex - 1],
        ...selectedImages.filter((_image, index) => index !== representativeImageIndex - 1),
      ].filter(Boolean)
    : selectedImages;
const representativeImage = representativeImageIndex ? selectedImages[representativeImageIndex - 1] ?? null : null;
const rewriteSelectedImageUrls = (html) => {
  if (typeof html !== 'string' || !html.trim()) return '';
  return selectedImages.reduce((acc, image) => {
    const originalUrl = String(image.url ?? '').trim();
    const protectedUrl = String(image.delivery_url ?? image.url ?? '').trim();
    if (!originalUrl || !protectedUrl || originalUrl === protectedUrl) return acc;
    return acc.split(originalUrl).join(protectedUrl);
  }, html);
};

const defaultAlt = (image, index) => {
  const roleLabel = image.before_after_role === 'before'
    ? '비포어'
    : image.before_after_role === 'after'
      ? '애프터'
      : '현장';
  const parts = [normalized.siteName, roleLabel, normalized.locationKr, normalized.businessTypeKr, image.product_name, image.color_name, image.caption]
    .map((item) => String(item ?? '').trim())
    .filter(Boolean);
  return truncate(parts.join(' - ') || `${normalized.siteName} ${roleLabel} 이미지 ${index + 1}`, 110);
};

const imageAltCandidates = toTextArray(parsed.image_alts ?? parsed.imageAlts ?? parsed.alt_texts ?? parsed.altTexts);
const imageCaptionCandidates = toTextArray(parsed.image_captions ?? parsed.imageCaptions ?? parsed.captions);
const imageAlts = selectedImagesForRender.map((image, index) => truncate(imageAltCandidates[index] || image.default_alt || defaultAlt(image, index), 125));
const imageCaptions = selectedImagesForRender.map((image, index) => String(
  imageCaptionCandidates[index]
  || image.caption
  || `${image.before_after_role === 'before' ? '비포어' : '애프터'} 이미지 ${index + 1}`
).trim());

const bodyHtmlRaw = parsed.body_html ?? parsed.bodyHtml ?? parsed.blog_body ?? rawContent;
let coreBodyHtml = typeof bodyHtmlRaw === 'string' && bodyHtmlRaw.trim()
  ? enforceEmailImageSizing(rewriteSelectedImageUrls(bodyHtmlRaw.trim()))
  : `<p>${escapeHtml(String(bodyHtmlRaw ?? '')).replace(/\n/g, '</p><p>')}</p>`;

if (humanTouch && !coreBodyHtml.includes(humanTouch)) {
  coreBodyHtml = `${coreBodyHtml}\n\n<section class=\"human-touch\"><p>${escapeHtml(humanTouch)}</p></section>`;
}

const imageSection = selectedImagesForRender.length
  ? `<section class="showroom-images"><h2>${normalized.beforeAfterAvailable ? '비포어 · 애프터 사진' : '현장 사진'}</h2>${selectedImagesForRender.map((image, index) => `<figure style="${figureStyle}"><img src="${escapeAttr(image.delivery_url ?? image.url)}" alt="${escapeAttr(imageAlts[index])}" width="640" loading="lazy" draggable="false" style="${emailImageStyle}" /><figcaption style="${captionStyle}">${escapeHtml(imageCaptions[index])}</figcaption></figure>`).join('')}</section>`
  : '';

const comparisonSection = beforeAfterPoints.length
  ? `<section class=\"before-after-summary\"><h2>달라진 점</h2><ul>${beforeAfterPoints.map((item) => `<li>${escapeHtml(item)}</li>`).join('')}</ul></section>`
  : '';

const geoSection = featuredAnswer || geoPoints.length
  ? `<section class="geo-summary"><h2>이 현장 먼저 보기</h2>${featuredAnswer ? `<p>${escapeHtml(featuredAnswer)}</p>` : ''}${geoPoints.length ? geoPoints.map((item) => `<p>${escapeHtml(item)}</p>`).join('') : ''}</section>`
  : '';

const faqSection = faqQas.length
  ? `<section class=\"faq-section\"><h2>자주 묻는 질문</h2>${faqQas.map((item) => `<article><h3>${escapeHtml(item.question)}</h3><p>${escapeHtml(item.answer)}</p></article>`).join('')}</section>`
  : '';

const hasImageTag = /<img\b/i.test(coreBodyHtml);
const bodyHtml = enforceEmailImageSizing([
  hasImageTag ? '' : imageSection,
  geoSection,
  comparisonSection,
  coreBodyHtml,
  faqSection,
].filter(Boolean).join('\n\n'));

const qualityPrompt = [
  '다음 네이버 블로그 초안이 파인드가구 홈페이지 쇼룸 사례 원고로 적절한지 검수하라.',
  '평가 기준:',
  '1. 공개명으로 external/public 이름만 쓰고 내부 현장명은 드러나지 않는지',
  '2. 사진 우선 구조가 자연스럽게 보이는지',
  '3. 섹션 수가 과하지 않고 읽기 쉬운지',
  '4. 제목과 요약의 명확성 및 SEO 키워드 반영',
  '4-1. 전달받은 SEO 설명이 있으면 제목/요약/본문의 검색 문맥에 자연스럽게 반영되었는지',
  '5. featured answer / FAQ 등 AEO 구조 적절성',
  '5-1. geo_points가 지역 키워드 나열이 아니라 문장형 정보로 작성되었는지',
  '6. before/after가 있으면 before 추정 금지와 after 메타 활용이 지켜졌는지',
  '7. 이미지 삽입 및 alt 텍스트/캡션 적절성',
  '8. 온라인 쇼룸/홈페이지 사례 비교 CTA가 과하지 않으면서 자연스럽게 이어지는지',
  '9. 네이버 블로그 특성상 첫 문단에서 핵심 답변과 검색 의도가 바로 연결되는지',
  '10. SEO/AEO/GEO 관점에서 정의형 문장, FAQ, 사례 문장이 인용 가능한 수준으로 정리됐는지',
  '응답은 JSON만 반환:',
  '{"score": 0-100, "pass": true/false, "reason": "string", "review_note": "string", "checklist": ["string"]}',
  '',
  `[제목]\n${title}`,
  '',
  `[요약]\n${summary}`,
  '',
  `[한 줄 코멘트]\n${humanTouch}`,
  '',
  `[본문 HTML]\n${bodyHtml}`,
  '',
  `[FAQ]\n${faqQas.map((item) => `Q. ${item.question}\nA. ${item.answer}`).join('\n\n')}`,
  '',
  `[이미지 ALT]\n${imageAlts.map((item, index) => `${index + 1}. ${item}`).join('\n')}`,
  '',
  `[메타]\n공개명=${normalized.siteName}\n내부명=${normalized.internalSiteName || '없음'}\n지역=${normalized.locationKr}\n업종=${normalized.businessTypeKr}\n제품=${normalized.productNames.join(', ')}\n컬러=${normalized.colorNames.join(', ')}\nSEO설명=${normalized.seoDescription || '없음'}\nCTA=${normalized.ctaText}`,
].join('\n');

const qualityRequestBody = {
  model: 'gpt-4.1-mini',
  temperature: 0.2,
  max_tokens: 1400,
  response_format: {
    type: 'json_object',
  },
  messages: [
    {
      role: 'system',
      content: '당신은 네이버 블로그 품질 검수 에디터다. 공개명 사용, 사진 우선 구조, 섹션 단순화, SEO/AEO/GEO, 첫 문단 답변 구조, 이미지 품질, 그리고 쇼룸을 오프라인 전시장이 아닌 홈페이지 내 온라인 사례 쇼룸 의미로 썼는지까지 함께 보수적으로 평가하고 JSON만 반환한다.',
    },
    {
      role: 'user',
      content: qualityPrompt,
    },
  ],
};

return [{
  json: {
    ...normalized,
    title,
    summary,
    featuredAnswer,
    beforeAfterPoints,
    humanTouch,
    bodyHtml,
    socialText,
    hashtags,
    seoKeywords,
    geoPoints,
    faqQas,
    imageAlts,
    imageCaptions,
    representativeImageIndex,
    representativeImageReason,
    representativeImageLabel: representativeImageIndex ? `${representativeImageIndex}번 이미지` : '',
    imageOrder,
    representativeImageUrl: representativeImage?.delivery_url ?? representativeImage?.url ?? '',
    rawDraft: rawContent,
    qualityRequestBody,
  },
}];

const draft = $('초안 정리 및 검수 요청 준비').first().json;
const response = $input.first().json ?? {};
const rawContent = response.choices?.[0]?.message?.content ?? '';

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (error) {
  parsed = {
    score: 0,
    pass: false,
    reason: '검수 응답 JSON 파싱 실패',
    review_note: rawContent,
    checklist: []
  };
}

const score = Number(parsed.score ?? parsed.quality_score ?? 0);
const qualityPassed = typeof parsed.pass === 'boolean'
  ? parsed.pass
  : score >= Number(draft.qualityThreshold ?? 85);

const checklist = Array.isArray(parsed.checklist)
  ? parsed.checklist.map((item) => String(item).trim()).filter(Boolean)
  : [];

return [{
  json: {
    ...draft,
    qualityScore: score,
    qualityPassed,
    qualityReason: parsed.reason ?? '',
    reviewNote: parsed.review_note ?? '',
    qualityChecklist: checklist,
    reviewedAt: new Date().toISOString()
  }
}];
